+{
+  const auto np = genicam_utils::find_node(nn, camera_, debug_);
+  if (!np) {
+    return ("node " + nn + " not found!");
+  }
+  std::string msg;
+  if (!common_checks(*np, nn, &msg)) {
+    return (msg);
+  }
+  auto p = static_cast<GenApi::CCommandPtr>(*np);
+  p->Execute();
+  return ("OK");
+}
