+void PointGreyCamera::setGain(const float& gain)
+{
+  // Turn auto gain off
+  pCam_->GainAuto.SetValue(Spinnaker::GainAutoEnums::GainAuto_Off);
+
+  // Set gain
+  setProperty("Gain", gain);
