+  void onInit()
+  {
+    // Get nodeHandles
+    ros::NodeHandle &nh = getMTNodeHandle();
+    ros::NodeHandle &pnh = getMTPrivateNodeHandle();
+    std::string firstcam;
+    pnh.param<std::string>("first_namespace", firstcam, "left");
+    ros::NodeHandle lnh(getMTNodeHandle(), firstcam);
