+        ros::Time time = ros::Time::now();
+        image->header.stamp = time;
+        second_image->header.stamp = time;
+        ci_->header.stamp = time;
+        rci_->header.stamp = time;
+        ci_->binning_x = binning_x_;
+        rci_->binning_x = binning_x_;
+        ci_->binning_y = binning_y_;
