+        rci_->roi.x_offset = roi_x_offset_;
+        ci_->roi.y_offset = roi_y_offset_;
+        rci_->roi.y_offset = roi_y_offset_;
+        ci_->roi.height = roi_height_;
+        rci_->roi.height = roi_height_;
